   154→void GrpcMuxImpl::sendDiscoveryRequest(absl::string_view type_url) {
   155→  if (shutdown_) {
   156→    return;
   157→  }
   158→
   159→  ApiState& api_state = apiStateFor(type_url);
   160→  auto& request = api_state.request_;
   161→  request.mutable_resource_names()->Clear();
   162→
   163→  // Maintain a set to avoid dupes.
   164→  absl::node_hash_set<std::string> resources;
   165→  for (const auto* watch : api_state.watches_) {
   166→    for (const std::string& resource : watch->resources_) {
   167→      if (!resources.contains(resource)) {
   168→        resources.emplace(resource);
   169→        request.add_resource_names(resource);
   170→      }
   171→    }
   172→  }
   173→
   174→  if (api_state.must_send_node_ || !skip_subsequent_node_ || first_stream_request_) {
   175→    // Node may have been cleared during a previous request.
   176→    request.mutable_node()->CopyFrom(local_info_.node());
   177→    api_state.must_send_node_ = false;
   178→  } else {
   179→    request.clear_node();
   180→  }
   181→  ENVOY_LOG(trace, "Sending DiscoveryRequest for {}: {}", type_url, request.ShortDebugString());
   182→  grpc_stream_->sendMessage(request);
   183→  first_stream_request_ = false;
   184→
   185→  // clear error_detail after the request is sent if it exists.
   186→  if (apiStateFor(type_url).request_.has_error_detail()) {
   187→    apiStateFor(type_url).request_.clear_error_detail();
   188→  }
   189→}
